div.style:
position: fixed;
top: 0;
left: 0;
width: 100%;
height: 100%;
z-index: 0;
display: flex;
align-items: center;
justify-content: center;
pointer-events: none;
overflow: hidden;

span.t-attf-style:
font-size: 160px;
font-weight: 900;
font-family: Arial, Helvetica, sans-serif;
letter-spacing: 8px;
text-transform: uppercase;
transform: rotate(-45deg);
white-space: nowrap;
color: #{'rgba(0,160,70,0.15)' if o.payment_watermark == 'cash' else 'rgba(0,90,200,0.15)'};
border: 6px solid #{'rgba(0,160,70,0.12)' if o.payment_watermark == 'cash' else 'rgba(0,90,200,0.12)'};
padding: 10px 30px;
border-radius: 12px;
user-select: none;
